### 2. **Focus on Trace IDs**

Ensure that your tracing implementation is focused on propagating and using trace IDs effectively.

#### Example: Propagating Trace ID in Flask Middleware

```python
from flask import Flask, request
from opentracing.ext import tags
from jaeger_client import Config

app = Flask(__name__)

def init_tracer(service_name):
    config = Config(
        config={
            'sampler': {'type': 'const', 'param': 1},
            'logging': True,
        },
        service_name=service_name,
        validate=True,
    )
    return config.initialize_tracer()

tracer = init_tracer("api-gateway")

@app.before_request
def before_request():
    span_ctx = tracer.extract(format='http_headers', carrier=request.headers)
    span = tracer.start_span(operation_name="gateway.request", child_of=span_ctx)

    # Set tags on the span
    span.set_tag(tags.HTTP_METHOD, request.method)
    span.set_tag(tags.HTTP_URL, request.url)

@app.after_request
def after_request(response):
    if 'X-B3-TraceId' in response.headers:
        tracer.inject(span.context(), format='http_headers', carrier=response.headers)
    return response

if __name__ == '__main__':
    app.run(host='0.0.0.0')
```

### 3. **Structured Logging with Trace IDs**

Ensure that your logging setup is configured to include trace IDs in structured logs.

#### Example: Structured Logging Configuration

```python
import logging
from flask import Flask, request
from jaeger_client import Config

app = Flask(__name__)

def init_tracer(service_name):
    config = Config(
        config={
            'sampler': {'type': 'const', 'param': 1},
            'logging': True,
        },
        service_name=service_name,
        validate=True,
    )
    return config.initialize_tracer()

tracer = init_tracer("api-gateway")

@app.before_request
def before_request():
    span_ctx = tracer.extract(format='http_headers', carrier=request.headers)
    span = tracer.start_span(operation_name="gateway.request", child_of=span_ctx)

    # Set tags on the span
    span.set_tag(tags.HTTP_METHOD, request.method)
    span.set_tag(tags.HTTP_URL, request.url)

@app.after_request
def after_request(response):
    if 'X-B3-TraceId' in response.headers:
        tracer.inject(span.context(), format='http_headers', carrier=response.headers)
    return response

# Configure structured logging with trace IDs
logging.basicConfig(level=logging.INFO,
                    format='%(asctime)s [%(levelname)s] %(message)s',
                    handlers=[logging.StreamHandler()])

@app.route('/')
def index():
    # Example of logging a message with trace ID
    log_message = f"Request received: {request.method} {request.url}"
    logging.info(log_message, extra={'trace_id': span.context().trace_id})

    return {"message": "Hello, World!"}

